import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  "Thế giới và gia tộc": z.object({
    "Địa điểm hiện tại": z.string().or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),
    "Tổng nhân khẩu gia tộc": z.coerce.number().prefault(0),
    "Số lượng tử tự còn sống": z.coerce.number().prefault(0),
    "Số lượng tử tự có Chân linh căn": z.coerce.number().prefault(0),
  }),

  "Bảng hệ thống": z.object({
    "Điểm tích lũy còn lại": z.coerce.number().prefault(0),
    "Log": z.string().describe('Thông báo hệ thống mới nhất').prefault('Hệ thống đang chờ lệnh...'),
    "Bị động đã kích hoạt": z.object({}).catchall(z.string().describe('Hiệu quả bị động')),
    "Thành tựu đã đạt": z.object({}).catchall(z.string().describe('Phần thưởng')),
    "Túi đồ": z.object({}).catchall(
      z.object({
        "Mô tả": z.string().or(z.literal('Không')).prefault('Không'),
        "Số lượng": z.coerce.number().prefault(1),
      })
    ),
  }),

  "Ký chủ": z.object({
    "Cảnh giới tu vi": z.string().or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),
    "Linh căn": z.string().or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),
    "Thọ nguyên": z.coerce.number().prefault(0),
    "Thể chất bổ sung": z.object({}).catchall(z.string().describe('Nguồn gốc thể chất')),
  }),

  "Đạo lữ lục": z.record(z.string().describe('Tên đạo lữ'), z.object({
    // Thông tin cơ bản
    "Cảnh giới tu vi": z.string().or(z.literal('Phàm nhân')).prefault('Phàm nhân'),
    "Linh căn": z.string().or(z.literal('Không')).prefault('Không'),
    "Hảo cảm": z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(50),
    "Độ phục tùng": z.coerce.number().describe('Ảnh hưởng từ điều giáo').transform(v => _.clamp(v, 0, 100)).prefault(0),

    // Cơ sở phồn diễn
    "Hiện tại có thụ thai không": z.boolean().prefault(false),
    "Số lượng tử tự đã sinh": z.coerce.number().prefault(0),

    // Chi tiết dữ liệu dò tìm NSFW và hệ thống
    "Dữ liệu dò tìm NSFW": z.object({
      "Đặc chất cơ thể": z.string().describe('Như danh khí, xử tử, ẩn tật, thuần âm thể v.v.').or(z.literal('Chờ dò tìm')).prefault('Chờ dò tìm'),
      "Chi tiết kinh nghiệm tình dục": z.string().describe('Số người đã kinh qua và trải nghiệm quá khứ').or(z.literal('Chưa rõ')).prefault('Chưa rõ'),
      "Phân bố vùng nhạy cảm": z.string().describe('Điểm nhạy cảm và điểm yếu trên cơ thể').or(z.literal('Chưa rõ')).prefault('Chưa rõ'),
      "Sở thích tình dục và XP": z.string().describe('Sở thích cách chơi ẩn').or(z.literal('Chưa rõ')).prefault('Chưa rõ'),
      "Độ khai phá cơ thể": z.string().describe('Giai đoạn điều giáo và độ chịu đựng').or(z.literal('Chưa khai phá')).prefault('Chưa khai phá'),
      "Tổng số lần giao phối": z.coerce.number().prefault(0),
      "Chi tiết trạng thái thai kỳ": z.string().describe('Tuần thai cụ thể, độ ổn định thai khí, kết quả dò tìm linh căn thai nhi').or(z.literal('Không')).prefault('Không')
    })
  }))
});

$(() => {
  registerMvuSchema(Schema);
})

