      $('#world-true-roots').text(_.get(sd, 'Thế giới và gia tộc.Số lượng tử tự có Chân linh căn', 0));

      /* Dữ liệu Ký chủ */
      $('#host-cultivation').text(_.get(sd, 'Ký chủ.Cảnh giới tu vi', 'Phàm nhân'));
      $('#host-root').text(_.get(sd, 'Ký chủ.Linh căn', 'Không'));
      $('#host-lifespan').text(_.get(sd, 'Ký chủ.Thọ nguyên', 0));

      /* Hiển thị Thể chất bổ sung */
      const extraPhysiques = _.get(sd, 'Ký chủ.Thể chất bổ sung', {});
      if (Object.keys(extraPhysiques).length === 0) {
        $('#host-physiques').html('<li class="ink-list-empty">Chưa có thể chất bổ sung.</li>');
      } else {
        let physiquesHtml = '';
        for (const [name, source] of Object.entries(extraPhysiques)) {
          physiquesHtml += `
            <li class="ink-list-item">
              <span class="ink-label">${name}</span>
              <span class="ink-value">${source}</span>
            </li>
          `;
        }
        $('#host-physiques').html(physiquesHtml);
      }

      /* Dữ liệu Bảng hệ thống */
      $('#sys-points').text(_.get(sd, 'Bảng hệ thống.Điểm tích lũy còn lại', 0));
       /* Cập nhật Log hệ thống */
      $('#sys-log-content').text(_.get(sd, 'Bảng hệ thống.Log', 'Đang chờ cập nhật...'));

      /* Hiển thị Bị động đã kích hoạt */
      const passives = _.get(sd, 'Bảng hệ thống.Bị động đã kích hoạt', {});
      if (Object.keys(passives).length === 0) {
        $('#sys-passives').html('<li class="ink-list-empty">Chưa kích hoạt bị động nào.</li>');
