        let passivesHtml = '';
        for (const [name, effect] of Object.entries(passives)) {
          passivesHtml += `
            <li class="ink-list-item">
              <span class="ink-label">${name}</span>
              <span class="ink-value">${effect}</span>
            </li>
          `;
        }
        $('#sys-passives').html(passivesHtml);
      }

      /* Hiển thị Thành tựu đã đạt */
      const achievements = _.get(sd, 'Bảng hệ thống.Thành tựu đã đạt', {});
      if (Object.keys(achievements).length === 0) {
        $('#sys-achievements').html('<li class="ink-list-empty">Chưa đạt được thành tựu nào.</li>');
      } else {
        let achievementsHtml = '';
        for (const [name, reward] of Object.entries(achievements)) {
          achievementsHtml += `
            <li class="ink-list-item">
              <span class="ink-label">${name}</span>
              <span class="ink-value">${reward}</span>
            </li>
          `;
