                    <span class="ink-label">Đặc chất cơ thể</span>
                    <span class="ink-value">${nsfw['Đặc chất cơ thể'] || 'Chưa rõ'}</span>
                  </li>
                  <li class="ink-list-item">
                    <span class="ink-label">Kinh nghiệm tình dục</span>
                    <span class="ink-value">${nsfw['Chi tiết kinh nghiệm tình dục'] || 'Chưa rõ'}</span>
                  </li>
                  <li class="ink-list-item">
                    <span class="ink-label">Vùng nhạy cảm</span>
                    <span class="ink-value">${nsfw['Phân bố vùng nhạy cảm'] || 'Chưa rõ'}</span>
                  </li>
                  <li class="ink-list-item">
