                  </li>
                  <li class="ink-list-item">
                    <span class="ink-label">Độ khai phá</span>
                    <span class="ink-value">${nsfw['Độ khai phá cơ thể'] || 'Chưa rõ'}</span>
                  </li>
                  <li class="ink-list-item">
                    <span class="ink-label">Tổng giao phối</span>
                    <span class="ink-value">${nsfw['Tổng số lần giao phối'] || 0}</span>
                  </li>
                  <li class="ink-list-item">
                    <span class="ink-label">Chi tiết thai kỳ</span>
                    <span class="ink-value">${nsfw['Chi tiết trạng thái thai kỳ'] || 'Không'}</span>
                  </li>
                </ul>
              </details>
            </article>
          `;
        }
        $('#partners-container').html(partnersHtml);
      }
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      populateCharacterData();

      /* Lắng nghe sự kiện cập nhật biến để tự động refresh */
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => {
        populateCharacterData();
      });

      /* Gắn sự kiện chuyển Tab */
      $('.ink-tab').on('click', function() {
        /* Xóa trạng thái active cũ */
        $('.ink-tab').removeClass('ink-tab--active');
        $('.ink-section').removeClass('active');

        /* Thêm active vào tab và section được chọn */
        $(this).addClass('ink-tab--active');
        const targetId = $(this).attr('data-target');
        $('#' + targetId).addClass('active');
      });
    }

    $(errorCatched(init));
  </script>
</head>
